member.example:
Bind the Collider isTrigger property using a serialized binder field — the target Collider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ColliderIsTriggerBinder _isTrigger;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isTrigger;
    }


Bind the Collider isTrigger property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Collider _collider;
        
        private ColliderIsTriggerBinder IsTrigger =>
            new(_collider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isTrigger;
    }
